// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

contract SquareXOSettlement {
    struct Settlement {
        bytes32 matchId;
        address reporter;
        address winner;
        uint8 winnerCode;
        uint256 stakeWei;
        uint256 timestamp;
    }

    mapping(bytes32 => Settlement) public settlements;

    event MatchSettled(
        bytes32 indexed matchId,
        address indexed reporter,
        address indexed winner,
        uint8 winnerCode,
        uint256 stakeWei
    );

    function settleMatch(bytes32 matchId, address winner, uint8 winnerCode) external payable {
        require(matchId != bytes32(0), 'INVALID_MATCH_ID');
        require(winnerCode <= 2, 'INVALID_WINNER_CODE');

        Settlement storage existing = settlements[matchId];
        require(existing.timestamp == 0, 'MATCH_ALREADY_SETTLED');

        if (winnerCode == 0) {
            require(winner == address(0), 'DRAW_WINNER_MUST_BE_ZERO');
        } else {
            require(winner != address(0), 'WINNER_REQUIRED');
        }

        settlements[matchId] = Settlement({
            matchId: matchId,
            reporter: msg.sender,
            winner: winner,
            winnerCode: winnerCode,
            stakeWei: msg.value,
            timestamp: block.timestamp
        });

        if (msg.value > 0) {
            if (winnerCode == 0) {
                payable(msg.sender).transfer(msg.value);
            } else {
                payable(winner).transfer(msg.value);
            }
        }

        emit MatchSettled(matchId, msg.sender, winner, winnerCode, msg.value);
    }
}

